#include <stdio.h>

#define N 4

int main(void) {
    int burst[] = {12, 8, 4, 10};
    int remaining[N];
    int response[N];
    int quantum = 2;
    int time = 0;
    int done = 0;

    for (int i = 0; i < N; i++) {
        remaining[i] = burst[i];
        response[i] = -1;
    }

    while (done < N) {
        for (int i = 0; i < N; i++) {
            if (remaining[i] > 0) {
                if (remaining[i] <= quantum) {
                    time += remaining[i];
                    remaining[i] = 0;
                    response[i] = time;
                    done++;
                } else {
                    time += quantum;
                    remaining[i] -= quantum;
                }
            }
        }
    }

    for (int i = 0; i < N; i++)
        printf("Response time P%d: %d\n", i + 1, response[i]);

    float avg = (float)(response[0] + response[1] + response[2] + response[3]) / N;
    printf("Average response time: %.2f\n", avg);
    return 0;
}

