void example_rr(void) {
    int rem[] = {4, 3};
    int resp[] = {-1, -1};
    int q = 2, t = 0, done = 0;
    while (done < 2) {
        for (int i = 0; i < 2; i++) {
            if (rem[i] > 0) {
                if (rem[i] <= q) { t += rem[i]; resp[i] = t; rem[i] = 0; done++; }
                else { t += q; rem[i] -= q; }
            }
        }
    }
    printf("P1 resp=%d P2 resp=%d\n", resp[0], resp[1]);
}

